Future<Either<Failure, User>> login(String email, String pass) async {
  try {
    final response = await api.login(email, pass);
    return Right(User.fromDto(response));
  } on DioException catch (e) {
    return Left(ServerFailure(e.message ?? ''));
  }
}

// Usage
